  ('elementary-8b44517b-moex-00974', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '公務員甲犯貪污治罪條例第4條第1項第5款對於違背職務之行為收受賄賂罪，則關於其自首或自白敘 述，下列何者正確？', '["於犯罪後自首，即應減輕或免除其刑", "在偵查中自白，得減輕或免除其刑", "在偵查中自白，如有所得並自動繳交全部所得財物者，減輕其刑", "在偵查中自白，如有所得並自動繳交全部所得財物者，減輕或免除其刑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
